package geofence_single
public

	with geofence_nodes;
	with base_types;

	system GeoFence_singleton
		features
			timeToRecovery: out data port real;
	annex agree {**
	  const t_init = 0.0;
	  const t_step = 0.1;
	  const recovery_time = 1.7;

	  assume "initial_t": t = t_init;
	  assume "t_step_size": t' = t + t_step;

	  guarantee "recovery_time_bound": timeToRecovery = recovery_time;

	  guarantee "distance_increasing": 
	    (t >= recovery_time) => (distanceFromFence > distanceFromFence@-1);
	**};
	end GeoFence_singleton;

	system implementation GeoFence_singleton.impl
	end GeoFence_singleton.impl;

	-- Type Aliases

	data int extends base_types::Integer
	end int;

	data real extends base_types::Float
	end real;

end geofence_single;

